1	import {
2	  brandReportRows,
3	  brands,
4	  domainReportRows,
5	  prompts,
6	  topics,
7	  untrackedQueries,
8	  urlReportRows,
9	} from "../../data/adblume-snapshot";
10	import type { BrandReportRow, Prompt, QueryGap } from "./types";
11	
12	const competitors = brands.filter((brand) => !brand.isOwn).map((brand) => brand.name);
13	
14	const positiveFitTerms = [
15	  "luxury",
16	  "fine jewelry",
17	  "jewelry",
18	  "editorial",
19	  "cinematic",
20	  "ai",
21	  "catalog",
22	  "ecommerce",
23	  "high-end",
24	  "dtc",
25	  "campaign",
26	  "video",
27	];
28	
29	const lowFitTerms = ["cheap", "free", "bulk-only", "generic product photos", "low cost"];
30	
31	function includesAny(text: string, terms: string[]) {
32	  return terms.some((term) => text.includes(term));
33	}
34	
35	function scoreByTerms(text: string, terms: string[], base = 0, step = 12, max = 100) {
36	  return Math.min(
37	    max,
38	    base + terms.reduce((score, term) => (text.includes(term) ? score + step : score), 0),
39	  );
40	}
41	
42	function classifyIntent(query: string): QueryGap["customerIntent"] {
43	  const text = query.toLowerCase();
44	  if (text.includes("adblume")) return "evaluate_adblume";
45	  if (includesAny(text, ["vs", "alternatives", "compare"])) return "compare_vendors";
46	  if (includesAny(text, ["ai", "tool", "retouching"])) return "explore_ai";
47	  if (includesAny(text, ["catalog", "shopify", "ecommerce", "marketplace"])) return "launch_ecommerce";
48	  return "hire_studio";
49	}
50	
51	function classifyFunnel(query: string): QueryGap["funnelStage"] {
52	  const text = query.toLowerCase();
53	  if (includesAny(text, ["vs", "alternatives", "pricing", "best", "service", "studio", "partner"])) {
54	    return "decision";
55	  }
56	  if (includesAny(text, ["compare", "tool", "how", "can"])) return "consideration";
57	  return "awareness";
58	}
59	
60	function routeAction(query: string): QueryGap["recommendedAction"] {
61	  const text = query.toLowerCase();
62	  if (text.includes("vs")) return "create_comparison_page";
63	  if (text.includes("alternatives")) return "create_alternatives_page";
64	  if (includesAny(text, ["how", "can", "what"])) return "create_faq_article";
65	  if (includesAny(text, ["best", "top"])) return text.includes("studio") ? "create_service_page" : "create_listicle";
66	  if (includesAny(text, ["video", "catalog", "service", "studio", "partner"])) return "create_service_page";
67	  return "source_outreach";
68	}
69	
70	function alignedPropositions(query: string) {
71	  const text = query.toLowerCase();
72	  const propositions = new Set<string>();
73	  if (includesAny(text, ["ai", "retouching", "tool"])) propositions.add("AI-assisted innovation");
74	  if (includesAny(text, ["luxury", "fine jewelry", "high-end", "dtc"])) propositions.add("Luxury aesthetic");
75	  if (includesAny(text, ["campaign", "cinematic", "video"])) propositions.add("Editorial-grade quality");
76	  if (includesAny(text, ["catalog", "ecommerce", "shopify", "marketplace"])) {
77	    propositions.add("Efficient/scalable production");
78	  }
79	  if (text.includes("jewelry")) propositions.add("Jewelry-specific expertise");
80	  return Array.from(propositions);
81	}
82	
83	function riskFlags(query: string) {
84	  const text = query.toLowerCase();
85	  const flags = lowFitTerms.filter((term) => text.includes(term)).map((term) => `Potentially off-positioning: ${term}`);
86	  if (text.includes("tool")) {
87	    flags.push("Query may imply a self-serve software tool; position Adblume as an AI-assisted service, not SaaS.");
88	  }
89	  return flags;
90	}
91	
92	function heuristicCompetitors(query: string) {
93	  const text = query.toLowerCase();
94	  if (text.includes("soona")) return ["Soona", "Squareshot", "ProductPhoto.com"];
95	  if (includesAny(text, ["ai", "tool", "retouching"])) return ["Soona", "Shhots AI", "Scalio"];
96	  if (includesAny(text, ["catalog", "ecommerce", "shopify"])) return ["Squareshot", "Pixelz", "ProductPhoto.com"];
97	  if (includesAny(text, ["luxury", "fine jewelry", "video", "campaign"])) return ["ESPOSTUDIO", "Studio Nula", "Pro Photo Studio"];
98	  return competitors.slice(0, 3);
99	}
100	
101	function brandDomainsFor(brandNames: string[]) {
102	  const normalized = new Set(brandNames.map((name) => name.toLowerCase()));
103	  return brands
104	    .filter((brand) => normalized.has(brand.name.toLowerCase()))
105	    .flatMap((brand) => brand.domains);
106	}
107	
108	function measuredSourcesFor(competitorRows: BrandReportRow[]) {
109	  const competitorNames = competitorRows.map((row) => row.brandName);
110	  const competitorDomains = new Set(brandDomainsFor(competitorNames));
111	  const citedDomains = domainReportRows
112	    .filter((row) => competitorDomains.has(row.domain) || row.classification === "UGC")
113	    .sort((a, b) => b.citationCount - a.citationCount)
114	    .slice(0, 4)
115	    .map((row) => row.domain);
116	  const sourceUrls = urlReportRows
117	    .filter((row) => {
118	      try {
119	        return competitorDomains.has(new URL(row.url).hostname.replace(/^www\./, ""));
120	      } catch {
121	        return false;
122	      }
123	    })
124	    .sort((a, b) => b.citationCount - a.citationCount)
125	    .slice(0, 4)
126	    .map((row) => row.url);
127	
128	  return { citedDomains, sourceUrls };
129	}
130	
131	function buildGap(
132	  id: string,
133	  query: string,
134	  topicName: string,
135	  gapState: QueryGap["gapState"],
136	  promptId?: string,
137	  measured?: {
138	    own?: BrandReportRow;
139	    competitors: BrandReportRow[];
140	  },
141	): QueryGap {
142	  const text = query.toLowerCase();
143	  const winningCompetitors = measured?.competitors
144	    .filter((row) => row.visibility > 0)
145	    .sort((a, b) => b.visibility - a.visibility)
146	    .slice(0, 5)
147	    .map((row) => ({
148	      brand: row.brandName,
149	      visibility: row.visibility,
150	      mentionCount: row.mentionCount,
151	      position: row.position,
152	    }));
153	  const ownVisibility = measured?.own?.visibility;
154	  const competitorVisibility = winningCompetitors?.[0]?.visibility;
155	  const visibilityGap =
156	    ownVisibility !== undefined && competitorVisibility !== undefined
157	      ? Math.max(0, competitorVisibility - ownVisibility)
158	      : undefined;
159	  const intentScore = scoreByTerms(text, ["best", "studio", "service", "partner", "pricing", "hire"], 22, 12);
160	  const sentimentFitScore = Math.max(12, scoreByTerms(text, positiveFitTerms, 18, 8) - riskFlags(query).length * 24);
161	  const competitorPressureScore = Math.min(
162	    100,
163	    scoreByTerms(text, ["vs", "alternatives", "compare", "best", "tool", "studio"], 12, 12) +
164	      Math.round((competitorVisibility ?? 0) * 45),
165	  );
166	  const adblumeFitScore = scoreByTerms(text, ["jewelry", "fine jewelry", "luxury", "ai", "video", "catalog", "ecommerce"], 20, 10);
167	  const contentGapScore = Math.min(
168	    100,
169	    scoreByTerms(text, ["pricing", "alternatives", "vs", "best", "service", "studio", "tool"], 18, 10) +
170	      Math.round((visibilityGap ?? 0) * 65),
171	  );
172	  const gapStateBonus =
173	    gapState === "measured_gap" ? Math.round((visibilityGap ?? 0) * 32) : gapState === "untracked_opportunity" ? 10 : 4;
174	  const riskPenalty = riskFlags(query).length * 18;
175	  const totalScore = Math.max(
176	    0,
177	    Math.min(
178	      100,
179	      Math.round(
180	        (intentScore + sentimentFitScore + competitorPressureScore + adblumeFitScore + contentGapScore) / 5 +
181	          gapStateBonus -
182	          riskPenalty,
183	      ),
184	    ),
185	  );
186	  const sources = measured ? measuredSourcesFor(measured.competitors) : undefined;
187	
188	  return {
189	    id,
190	    query,
191	    promptId,
192	    topicName,
193	    customerIntent: classifyIntent(query),
194	    funnelStage: classifyFunnel(query),
195	    gapState,
196	    intentScore,
197	    sentimentFitScore,
198	    competitorPressureScore,
199	    adblumeFitScore,
200	    contentGapScore,
201	    totalScore,
202	    scoreLabel: totalScore >= 78 ? "High" : totalScore >= 58 ? "Medium" : "Low",
203	    likelyCompetitors: winningCompetitors?.length
204	      ? winningCompetitors.map((competitor) => competitor.brand)
205	      : heuristicCompetitors(query),
206	    alignedPropositions: alignedPropositions(query),
207	    riskFlags: riskFlags(query),
208	    approvalStatus: totalScore >= 78 ? "approved" : "pending",
209	    recommendedAction: routeAction(query),
210	    ownVisibility,
211	    competitorVisibility,
212	    visibilityGap,
213	    mentionCount: measured?.own?.mentionCount,
214	    sentiment: measured?.own?.sentiment,
215	    position: measured?.own?.position,
216	    citedDomains: sources?.citedDomains,
217	    sourceUrls: sources?.sourceUrls,
218	    winningCompetitors,
219	  };
220	}
221	
222	function topicNameForPrompt(prompt: Prompt) {
223	  return topics.find((topic) => topic.id === prompt.topicId)?.name ?? "Uncategorized";
224	}
225	
226	export function getQueryGaps() {
227	  const ownBrand = brands.find((brand) => brand.isOwn);
228	  const tracked = prompts.map((prompt) => {
229	    const rows = brandReportRows.filter((row) => row.promptId === prompt.id);
230	    const own = rows.find((row) => row.brandId === ownBrand?.id);
231	    const competitorRows = rows.filter((row) => row.brandId !== ownBrand?.id);
232	    return buildGap(
233	      `gap-${prompt.id}`,
234	      prompt.text,
235	      topicNameForPrompt(prompt),
236	      rows.length ? "measured_gap" : "tracked_pending",
237	      prompt.id,
238	      rows.length ? { own, competitors: competitorRows } : undefined,
239	    );
240	  });
241	  const untracked = untrackedQueries.map((query) =>
242	    buildGap(query.id, query.query, query.topicName, "untracked_opportunity"),
243	  );
244	  return [...tracked, ...untracked].sort((a, b) => b.totalScore - a.totalScore);
245	}
246	
247	export function summarizeByIntent(gaps: QueryGap[]) {
248	  return Object.values(
249	    gaps.reduce<Record<string, { intent: QueryGap["customerIntent"]; count: number; score: number; approved: number }>>(
250	      (summary, gap) => {
251	        const current = summary[gap.customerIntent] ?? {
252	          intent: gap.customerIntent,
253	          count: 0,
254	          score: 0,
255	          approved: 0,
256	        };
257	        current.count += 1;
258	        current.score += gap.totalScore;
259	        if (gap.approvalStatus === "approved") current.approved += 1;
260	        summary[gap.customerIntent] = current;
261	        return summary;
262	      },
263	      {},
264	    ),
265	  )
266	    .map((item) => ({ ...item, averageScore: Math.round(item.score / item.count) }))
267	    .sort((a, b) => b.averageScore - a.averageScore);
268	}
