    .sort((a, b) => b.citationCount - a.citationCount)
    .slice(0, 4)
    .map((row) => row.domain);
  const sourceUrls = urlReportRows
    .filter((row) => {
      try {
        return competitorDomains.has(new URL(row.url).hostname.replace(/^www\./, ""));
      } catch {
        return false;
      }
    })
    .sort((a, b) => b.citationCount - a.citationCount)
    .slice(0, 4)
    .map((row) => row.url);

  return { citedDomains, sourceUrls };
}

function buildGap(
