import {
  BarChart3,
  CheckCircle2,
  ClipboardCheck,
  Compass,
  Download,
  Eye,
  FileText,
  Gauge,
  Search,
  Settings2,
  ShieldCheck,
  Sparkles,
  TriangleAlert,
