import { Router, Request, Response } from "express";
import {
  fetchBrandsList,
  fetchTopicsList,
  fetchPromptsList,
  fetchBrandReportRows,
  fetchDomainReportRows,
  fetchUrlReportRows,
  isPeecConfigured,
} from "../services/peec.js";

const router = Router();

interface SnapshotBrand {
  id: string;
  name: string;
  domains: string[];
  aliases?: string[];
  isOwn: boolean;
}

interface SnapshotTopic {
  id: string;
  name: string;
}

interface SnapshotPrompt {
  id: string;
  text: string;
  topicId: string;
  tagIds: string[];
  countryCode: "US";
}

interface SnapshotBrandRow {
  promptId: string;
  brandId: string;
  brandName: string;
  visibility: number;
  mentionCount: number;
  shareOfVoice: number;
  sentiment: number | null;
  position: number | null;
}

interface SnapshotDomainRow {
  domain: string;
  classification: string;
  retrievedPercentage: number;
  retrievalRate: number;
  citationRate: number;
  retrievalCount: number;
  citationCount: number;
  mentionedBrandIds: string[];
}

interface SnapshotUrlRow {
  url: string;
  classification: string;
  title: string;
  citationCount: number;
  retrievalCount: number;
  citationRate: number;
  mentionedBrandIds: string[];
}

interface Snapshot {
  project: { id: string; name?: string; chatCount: number; reportDate: string; reportStatus: string };
  brandProfile: { name: string; domain: string; description: string; propositions: string[] };
  brands: SnapshotBrand[];
  topics: SnapshotTopic[];
  prompts: SnapshotPrompt[];
  brandReportRows: SnapshotBrandRow[];
  domainReportRows: SnapshotDomainRow[];
  urlReportRows: SnapshotUrlRow[];
  untrackedQueries: Array<{ id: string; query: string; topicName: string }>;
}

function asString(v: unknown, fallback = ""): string {
  return typeof v === "string" ? v : fallback;
}
function asNumber(v: unknown, fallback = 0): number {
  return typeof v === "number" && Number.isFinite(v) ? v : fallback;
}
function asNumberOrNull(v: unknown): number | null {
  return typeof v === "number" && Number.isFinite(v) ? v : null;
}
function asStringArray(v: unknown): string[] {
  return Array.isArray(v) ? v.filter((x): x is string => typeof x === "string") : [];
}
function pick<T = unknown>(obj: Record<string, unknown>, ...keys: string[]): T | undefined {
  for (const k of keys) {
    if (obj[k] !== undefined && obj[k] !== null) return obj[k] as T;
  }
  return undefined;
}

function normalizeBrand(raw: unknown): SnapshotBrand | null {
  if (!raw || typeof raw !== "object") return null;
  const r = raw as Record<string, unknown>;
  const id = asString(pick(r, "id", "brand_id"));
  const name = asString(pick(r, "name", "brand_name"));
  if (!id || !name) return null;
  return {
    id,
    name,
    domains: asStringArray(pick(r, "domains")),
    aliases: asStringArray(pick(r, "aliases")) || undefined,
    isOwn: Boolean(pick(r, "is_own", "isOwn")),
  };
}

function normalizeTopic(raw: unknown): SnapshotTopic | null {
  if (!raw || typeof raw !== "object") return null;
  const r = raw as Record<string, unknown>;
  const id = asString(pick(r, "id", "topic_id"));
  const name = asString(pick(r, "name", "title"));
  if (!id) return null;
  return { id, name: name || "Untitled topic" };
}

function normalizePrompt(raw: unknown): SnapshotPrompt | null {
  if (!raw || typeof raw !== "object") return null;
  const r = raw as Record<string, unknown>;
  const id = asString(pick(r, "id", "prompt_id"));
  const text = asString(pick(r, "text", "prompt_text", "query"));
  if (!id) return null;
  return {
    id,
    text: text || id,
    topicId: asString(pick(r, "topic_id", "topicId")),
    tagIds: asStringArray(pick(r, "tag_ids", "tagIds")),
    countryCode: "US",
  };
}

function normalizeBrandRow(raw: unknown): SnapshotBrandRow | null {
  if (!raw || typeof raw !== "object") return null;
  const r = raw as Record<string, unknown>;
  const promptId = asString(pick(r, "prompt_id", "promptId"));
  const brandId = asString(pick(r, "brand_id", "brandId"));
  if (!promptId || !brandId) return null;
  return {
    promptId,
    brandId,
    brandName: asString(pick(r, "brand_name", "brandName")),
    visibility: asNumber(pick(r, "visibility")),
    mentionCount: asNumber(pick(r, "mention_count", "mentionCount")),
    shareOfVoice: asNumber(pick(r, "share_of_voice", "shareOfVoice")),
    sentiment: asNumberOrNull(pick(r, "sentiment", "sentiment_score")),
    position: asNumberOrNull(pick(r, "position", "average_position", "rank")),
  };
}

function normalizeDomainRow(raw: unknown): SnapshotDomainRow | null {
  if (!raw || typeof raw !== "object") return null;
  const r = raw as Record<string, unknown>;
  const domain = asString(pick(r, "domain"));
  if (!domain) return null;
  const mentionedBrandsRaw = pick<unknown[]>(r, "mentioned_brands", "mentionedBrands") ?? [];
  const mentionedBrandIds = Array.isArray(mentionedBrandsRaw)
    ? mentionedBrandsRaw
        .map((b) => {
          if (typeof b === "string") return b;
          if (b && typeof b === "object") {
            const o = b as Record<string, unknown>;
            return asString(pick(o, "id", "brand_id"));
          }
          return "";
        })
        .filter(Boolean)
    : [];
  return {
    domain,
    classification: asString(pick(r, "classification"), "OTHER"),
    retrievedPercentage: asNumber(pick(r, "retrieved_percentage", "retrievedPercentage")),
    retrievalRate: asNumber(pick(r, "retrieval_rate", "retrievalRate")),
    citationRate: asNumber(pick(r, "citation_rate", "citationRate")),
    retrievalCount: asNumber(pick(r, "retrieval_count", "retrievalCount")),
    citationCount: asNumber(pick(r, "citation_count", "citationCount")),
    mentionedBrandIds,
  };
}

function normalizeUrlRow(raw: unknown): SnapshotUrlRow | null {
  if (!raw || typeof raw !== "object") return null;
  const r = raw as Record<string, unknown>;
  const url = asString(pick(r, "url"));
  if (!url) return null;
  const mentionedBrandsRaw = pick<unknown[]>(r, "mentioned_brands", "mentionedBrands") ?? [];
  const mentionedBrandIds = Array.isArray(mentionedBrandsRaw)
    ? mentionedBrandsRaw
        .map((b) => {
          if (typeof b === "string") return b;
          if (b && typeof b === "object") {
            const o = b as Record<string, unknown>;
            return asString(pick(o, "id", "brand_id"));
          }
          return "";
        })
        .filter(Boolean)
    : [];
  return {
    url,
    classification: asString(pick(r, "classification"), "OTHER"),
    title: asString(pick(r, "title"), url),
    citationCount: asNumber(pick(r, "citation_count", "citationCount")),
    retrievalCount: asNumber(pick(r, "retrieval_count", "retrievalCount")),
    citationRate: asNumber(pick(r, "citation_rate", "citationRate")),
    mentionedBrandIds,
  };
}

router.get("/snapshot", async (req: Request, res: Response) => {
  const peecProjectId = asString(req.query.peecProjectId).trim();
  const brandName = asString(req.query.brandName).trim();
  const projectName = asString(req.query.projectName).trim();

  if (!peecProjectId) {
    return res.status(400).json({ error: "peecProjectId is required", code: "BAD_REQUEST" });
  }

  if (!isPeecConfigured()) {
    return res.status(503).json({
      error: "Peec AI not configured. Set PEEC_API_KEY in .env to enable live data.",
      code: "PEEC_NOT_CONFIGURED",
    });
  }

  try {
    const [brandsRaw, topicsRaw, promptsRaw, brandRowsRaw, domainRowsRaw, urlRowsRaw] =
      await Promise.allSettled([
        fetchBrandsList(peecProjectId),
        fetchTopicsList(peecProjectId),
        fetchPromptsList(peecProjectId),
        fetchBrandReportRows(peecProjectId),
        fetchDomainReportRows(peecProjectId),
        fetchUrlReportRows(peecProjectId),
      ]);

    const settled = <T>(s: PromiseSettledResult<T[]>): T[] =>
      s.status === "fulfilled" ? s.value : [];

    const brands = settled(brandsRaw)
      .map(normalizeBrand)
      .filter((b): b is SnapshotBrand => b !== null);

    const topics = settled(topicsRaw)
      .map(normalizeTopic)
      .filter((t): t is SnapshotTopic => t !== null);

    let prompts = settled(promptsRaw)
      .map(normalizePrompt)
      .filter((p): p is SnapshotPrompt => p !== null);

    const brandReportRows = settled(brandRowsRaw)
      .map(normalizeBrandRow)
      .filter((r): r is SnapshotBrandRow => r !== null);

    const domainReportRows = settled(domainRowsRaw)
      .map(normalizeDomainRow)
      .filter((r): r is SnapshotDomainRow => r !== null);

    const urlReportRows = settled(urlRowsRaw)
      .map(normalizeUrlRow)
      .filter((r): r is SnapshotUrlRow => r !== null);

    if (!prompts.length && brandReportRows.length) {
      const seen = new Set<string>();
      prompts = brandReportRows
        .filter((r) => {
          if (seen.has(r.promptId)) return false;
          seen.add(r.promptId);
          return true;
        })
        .map((r) => ({
          id: r.promptId,
          text: r.promptId,
          topicId: "",
          tagIds: [],
          countryCode: "US" as const,
        }));
    }

    let resolvedOwnBrand = brands.find((b) => b.isOwn);
    if (!resolvedOwnBrand && brandName) {
      const lc = brandName.toLowerCase();
      resolvedOwnBrand = brands.find((b) => b.name.toLowerCase() === lc) ?? brands[0];
      if (resolvedOwnBrand) resolvedOwnBrand.isOwn = true;
    }

    const ownBrandName = resolvedOwnBrand?.name || brandName || "Your brand";
    const ownBrandDomain = resolvedOwnBrand?.domains[0] ?? "";

    const today = new Date().toISOString().split("T")[0];
    const snapshot: Snapshot = {
      project: {
        id: peecProjectId,
        name: projectName || undefined,
        chatCount: brandReportRows.length,
        reportDate: today,
        reportStatus: brandReportRows.length
          ? `Live Peec data fetched ${today} across ${prompts.length} tracked prompts.`
          : `No measured Peec rows for project on ${today}. Add prompts in Peec to populate this view.`,
      },
      brandProfile: {
        name: ownBrandName,
        domain: ownBrandDomain,
        description: `${ownBrandName}'s tracked positioning. Update brief in Settings to refine claims and propositions.`,
        propositions: [],
      },
      brands,
      topics,
      prompts,
      brandReportRows,
      domainReportRows,
      urlReportRows,
      untrackedQueries: [],
    };

    res.json(snapshot);
  } catch (error) {
    console.error("[gap-engine/snapshot] error:", error);
    const message = error instanceof Error ? error.message : "Unknown error";
    res.status(502).json({ error: message, code: "PEEC_FETCH_FAILED" });
  }
});

export default router;

