import { useQuery } from "@tanstack/react-query";
import type { Snapshot } from "../lib/gap-engine/types";

interface FetchArgs {
  peecProjectId: string;
  brandName: string;
  projectName: string;
}

async function fetchSnapshot({ peecProjectId, brandName, projectName }: FetchArgs): Promise<Snapshot> {
  const params = new URLSearchParams({ peecProjectId, brandName, projectName });
  const res = await fetch(`/api/gap-engine/snapshot?${params.toString()}`);
  if (!res.ok) {
    const body = await res.json().catch(() => ({ error: res.statusText }));
    throw new Error((body as { error?: string }).error || `Snapshot fetch failed: ${res.status}`);
  }
  return res.json();
}

export function useGapEngineSnapshot(args: FetchArgs) {
  return useQuery({
    queryKey: ["gap-engine-snapshot", args.peecProjectId],
    queryFn: () => fetchSnapshot(args),
    enabled: Boolean(args.peecProjectId),
    staleTime: 60_000,
  });
}

