export default function GapEngine() {
  const selection = useCurrentSelection();

  if (!selection.isConfigured) {
    return (
      <PageShell>
        <section className="panel" style={{ padding: 32, textAlign: "center" }}>
          <p className="muted">
            No project/brand selected. Choose one in{" "}
            <Link to="/settings" style={{ textDecoration: "underline" }}>
              Settings
            </Link>{" "}
            to run the gap engine.
          </p>
        </section>
      </PageShell>
    );
  }

  return (
    <GapEngineFetcher
      peecProjectId={selection.projectId}
      brandName={selection.brandName}
      projectName={selection.projectName}
    />
  );
}

function GapEngineFetcher({
  peecProjectId,
  brandName,
  projectName,
}: {
  peecProjectId: string;
  brandName: string;
  projectName: string;
}) {
  const { data, isLoading, error, refetch, isFetching } = useGapEngineSnapshot({
    peecProjectId,
    brandName,
    projectName,
  });

  if (isLoading) {
    return (
      <PageShell>
        <section className="panel" style={{ padding: 32, textAlign: "center" }}>
          <p className="muted">Loading Peec data for {brandName}…</p>
        </section>
      </PageShell>
    );
  }

  if (error) {
    return (
      <PageShell>
        <section className="panel" style={{ padding: 32, textAlign: "center" }}>
          <p className="muted">Failed to load gap-engine data: {(error as Error).message}</p>
          <button type="button" onClick={() => refetch()} style={{ marginTop: 12 }}>
            Retry
          </button>
        </section>
      </PageShell>
    );
  }

  if (!data || (data.prompts.length === 0 && data.brandReportRows.length === 0)) {
    return (
      <PageShell>
        <section className="panel" style={{ padding: 32, textAlign: "center" }}>
          <p className="muted">
            No measured Peec data for <strong>{brandName}</strong> yet. Add prompts and let Peec collect chats, then refresh.
          </p>
          <button type="button" onClick={() => refetch()} style={{ marginTop: 12 }}>
            Refresh
          </button>
        </section>
      </PageShell>
    );
  }

  return <GapEngineBody snapshot={data} brandName={brandName} projectName={projectName} isFetching={isFetching} />;
}

function GapEngineBody({
  snapshot,
  brandName,
  projectName,
  isFetching,
}: {
  snapshot: Snapshot;
  brandName: string;
  projectName: string;
  isFetching: boolean;
}) {
  const ctx = useMemo<BrandContext>(
    () => ({ brandName, ownBrandKey: brandName.toLowerCase() }),
    [brandName],
  );
  const initialGaps = useMemo(() => getQueryGaps(ctx, snapshot), [ctx, snapshot]);

