3	// Peec AI REST API Configuration
4	const API_BASE_URL = "https://api.peec.ai/customer/v1";
5	
6	export interface PeecConfig {
7	  apiKey?: string;
8	  projectId?: string;
9	}
10	
11	// Lazy initialization - don't read env vars at module load time
12	let config: PeecConfig | null = null;
13	
14	function getConfig(): PeecConfig {
15	  if (!config) {
16	    config = {
17	      apiKey: process.env.PEEC_API_KEY,
18	      projectId: process.env.PEEC_PROJECT_ID,
19	    };
20	  }
21	  return config;
22	}
23	
24	export function configurePeec(newConfig: Partial<PeecConfig>) {
25	  config = { ...getConfig(), ...newConfig };
26	}
27	
28	/**
29	 * The analyzer no longer requires PEEC_PROJECT_ID from env — the active Peec
30	 * project is selected in Settings and threaded through each request. Only the
31	 * API key needs to be configured at the process level.
32	 */
33	export function isPeecConfigured(): boolean {
34	  return !!getConfig().apiKey;
35	}
36	
37	function resolveProjectId(projectId?: string): string {
38	  const resolved = projectId?.trim() || getConfig().projectId;
39	  if (!resolved) {
40	    throw new Error(
41	      "Peec project_id missing. Select a project in Settings or set PEEC_PROJECT_ID in .env."
42	    );
43	  }
44	  return resolved;
45	}
46	
47	// Helper to make API requests
48	async function apiRequest(endpoint: string, body: Record<string, unknown>): Promise<unknown> {
49	  const cfg = getConfig();
50	
51	  if (!cfg.apiKey) {
52	    throw new Error("PEEC_API_KEY not configured. Set it in your .env file.");
53	  }
54	
55	  const response = await fetch(`${API_BASE_URL}${endpoint}`, {
56	    method: "POST",
57	    headers: {
58	      "Content-Type": "application/json",
59	      "X-API-Key": cfg.apiKey,
60	    },
61	    body: JSON.stringify(body),
62	  });
63	
64	  if (!response.ok) {
65	    const errorText = await response.text();
66	    throw new Error(`Peec API error (${response.status}): ${errorText}`);
67	  }
68	
69	  return response.json();
70	}
71	
72	// Helper for GET requests
73	async function apiGet(endpoint: string): Promise<unknown> {
74	  const cfg = getConfig();
75	
76	  if (!cfg.apiKey) {
77	    throw new Error("PEEC_API_KEY not configured. Set it in your .env file.");
78	  }
79	
80	  const response = await fetch(`${API_BASE_URL}${endpoint}`, {
81	    method: "GET",
82	    headers: {
83	      "X-API-Key": cfg.apiKey,
84	    },
85	  });
86	
87	  if (!response.ok) {
88	    const errorText = await response.text();
89	    throw new Error(`Peec API error (${response.status}): ${errorText}`);
90	  }
91	
92	  return response.json();
93	}
94	
95	// Get date range for last 30 days
96	function getDateRange(): { start_date: string; end_date: string } {
97	  const end = new Date();
98	  const start = new Date();
99	  start.setDate(start.getDate() - 30);
100	
101	  return {
102	    start_date: start.toISOString().split("T")[0],
103	    end_date: end.toISOString().split("T")[0],
104	  };
105	}
106	
107	export async function fetchBrandReport(
108	  _brandName: string,
109	  projectId?: string
110	): Promise<unknown> {
111	  if (!isPeecConfigured()) {
112	    throw new Error("Peec AI not configured. Set PEEC_API_KEY in .env");
113	  }
114	
115	  const project_id = resolveProjectId(projectId);
